// ============================================
// PARSER PROFESSIONALE SITESBOS + SOCIAL MAPPING
// ============================================

const item = $input.first().json;

// 1. ESTREZIONE DATI ORIGINALI
const msj = item.MiniSiteJson || {};
const hp = item.HoneyPot || {};
const od = item.owner_data || item.ownerdata || {};
const ob = item.owner_bot || item.ownerbot || {};
const catalogData = item.service_catalog_setup || {};

// 2. LOGICA INIEZIONE SERVIZI ATTIVI (SOLO COMMERCIAL: SER & PRO)
const activeCommercialAssets = [];
if (catalogData.categories && Array.isArray(catalogData.categories)) {
    catalogData.categories.forEach(category => {
        const isCommercialMacro = (category.macrocategories === "SER" || category.macrocategories === "PRO");
        if (isCommercialMacro && category.subcategories && Array.isArray(category.subcategories)) {
            category.subcategories.forEach(asset => {
                if (asset.blueprint_ready === true) {
                    activeCommercialAssets.push({
                        macro: category.macrocategories,
                        category: category.name,
                        category_short: category.short_name,
                        name: asset.name,
                        short_name: asset.short_name,
                        callback_data: asset.callback_data,
                        original_slug: asset.original_slug || null
                    });
                }
            });
        }
    });
}

// 3. COSTRUZIONE PAYLOAD ATOMICO PER L'EDITOR
const payload = {
    success: true,
    template: msj.style || "dark-tech", 

    HoneyPot: {
        ...hp,
        assets: hp.assets || {
            logo: { url: "", meta: { colors: ["#212D67", "#895FE0", "#FFFFFF"] } },
            photo: { url: "" },
            gallery1: { url: "" },
            gallery2: { url: "" },
            gallery3: { url: "" }
        },
        company_context_string: hp.company_context_string || od.business_description || "",
        offer_text: hp.offer_text || "",
        active_services: activeCommercialAssets,
        active_services_count: activeCommercialAssets.length,
        knowledge_fragments: hp.knowledge_fragments || [],
        availability_schedule: hp.availability_schedule || { hours: {} }
    },

    ownerdata: {
        ragione_sociale: od.ragione_sociale || od.ragionesociale || "",
        vat_number: od.vat_number || od.vatnumber || "",
        email: od.email || "",
        phone: od.phone || "",
        site: od.site || od.website || "",
        // --- MAPPATURA SOCIAL ---
        linkedin: od.linkedin_page || od.linkedin || "",
        facebook: od.facebook_page || od.facebook || "",
        instagram: od.instagram_page || od.instagram || "",
        twitter: od.twitter_page || od.twitter || ""
    },

    MiniSiteJson: {
        ...msj,
        seo: {
            title: msj.seo?.title || "",
            description: msj.seo?.description || "",
            keywords: msj.seo?.keywords || [],
            faq: msj.seo?.faq || []
        },
        hero: {
            h1: msj.hero?.h1 || "",
            sub: msj.hero?.sub || ""
        },
        design: {
            font: msj.design?.font || "Plus Jakarta Sans",
            radius: msj.design?.radius || "24px"
        },
        sections: {
            about: {
                headline: msj.sections?.about?.headline || "",
                body: msj.sections?.about?.body || ""
            },
            usp: Array.isArray(msj.sections?.usp) ? msj.sections.usp : [],
            process: Array.isArray(msj.sections?.process) ? msj.sections.process : []
        },
        service_descriptions: Array.isArray(msj.service_descriptions) ? msj.service_descriptions : []
    },

    ownerbot: {
        username: ob.username || "",
        first_name: ob.first_name || ""
    }
};

return [{ json: payload }];

const root = $input.first().json;

// ======================================================
// 1. DATI INPUT
// ======================================================
const hp = root.HoneyPot || {};
const od = root.owner_data || {};
const ai = root.MiniSiteJson || {};
const bot = root.owner_bot || {};

const assets = hp.assets || {};
const seo = ai.seo || {};
const hero = ai.hero || {};
const design = ai.design || {};
const sections = ai.sections || {};
const knowledgeFragments = Array.isArray(hp.knowledge_fragments) ? hp.knowledge_fragments : [];
const activeServices = Array.isArray(hp.active_services) ? hp.active_services : [];
const serviceDescriptions = Array.isArray(ai.service_descriptions) ? ai.service_descriptions : [];

// ======================================================
// 2. HELPERS
// ======================================================
const normalizeUrl = (value) => {
  let v = String(value || '').trim();
  if (!v) return '';
  if (v.startsWith('https://') || v.startsWith('http://')) return v;
  if (v.startsWith('https')) return 'https://' + v.slice(5);
  if (v.startsWith('http')) return 'http://' + v.slice(4);
  return 'https://' + v;
};

const esc = (txt) => {
  return String(txt || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
};

const clean = (txt) => {
  return String(txt || '')
    .replace(/\*\*(.*?)\*\*/g, '<b>$1</b>')
    .replace(/<br\s*\/?>/gi, '<br>')
    .replace(/\\n/g, '<br>');
};

const stripHtml = (txt) => {
  return String(txt || '')
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/<\/?(b|strong|i|em|u)>/gi, '')
    .replace(/\s+/g, ' ')
    .trim();
};

const uniqueBy = (arr, keyFn) => {
  const seen = new Set();
  return arr.filter((item) => {
    const key = keyFn(item);
    if (!key || seen.has(key)) return false;
    seen.add(key);
    return true;
  });
};

const getEmoji = (txt) => {
  const source = String(txt || '');
  const match = source.match(/\p{Emoji_Presentation}|\p{Extended_Pictographic}/u);
  return match ? match[0] : '•';
};

const formatHours = (d) => {
  if (!d) return 'Chiuso';
  const morning = d.morning?.from && d.morning?.to ? `${d.morning.from} - ${d.morning.to}` : '';
  const afternoon = d.afternoon?.from && d.afternoon?.to ? `${d.afternoon.from} - ${d.afternoon.to}` : '';
  const result = [morning, afternoon].filter(Boolean).join(' · ');
  return result || 'Chiuso';
};

const extractOfferTitle = (html) => {
  const text = stripHtml(String(html || '')).replace(/⚙️|👉|✨|🔸/g, '').trim();
  if (!text) return 'Offerta';
  const firstSentence = text.split('?')[0]?.trim();
  if (firstSentence && firstSentence.length <= 90) return firstSentence;
  return 'Offerta';
};

// ======================================================
// 3. DATI NORMALIZZATI
// ======================================================
const companyName = od.ragione_sociale || bot.first_name || 'Azienda';
const founderName = [od.name || '', od.surname || ''].join(' ').trim();
const telegramLink = bot.username ? `https://t.me/${bot.username}` : '';

const siteUrl = normalizeUrl(od.site || '');
const linkedinUrl = normalizeUrl(od.linkedin_page || '');
const facebookUrl = normalizeUrl(od.facebook_page || '');
const instagramUrl = normalizeUrl(od.instagram_page || '');
const twitterUrl = normalizeUrl(od.twitter_page || '');

const email = od.email || '';
const phone = od.phone || '';
const address = od.indirizzo || '';
const vat = od.vat_number || '';

const images = {
  logo: normalizeUrl(assets.logo?.url || ''),
  hero: normalizeUrl(assets.gallery1?.url || ''),
  about: normalizeUrl(assets.gallery2?.url || ''),
  process: normalizeUrl(assets.gallery3?.url || ''),
  founder: normalizeUrl(assets.photo?.url || ''),
};

const theme = {
  primary: assets.logo?.meta?.colors?.[0] || '#212D67',
  accent: assets.logo?.meta?.colors?.[1] || '#895FE0',
  white: assets.logo?.meta?.colors?.[2] || '#FFFFFF'
};

const keywords = Array.isArray(seo.keywords) ? seo.keywords : [];
const keywordsList = keywords.join(', ');

const heroTitle = hero.h1 || companyName;
const heroSub = hero.sub || hp.company_context_string || od.business_description || '';

const aboutKicker = sections.about?.kicker || 'Profilo';
const aboutHeadline = sections.about?.headline || companyName;
const aboutBody = sections.about?.body || hp.company_context_string || od.business_description || '';

const usp = Array.isArray(sections.usp) ? sections.usp : [];
const processSteps = Array.isArray(sections.process) ? sections.process : [];
const faqFromSeo = Array.isArray(seo.faq) ? seo.faq : [];

const serviceMap = {};
serviceDescriptions.forEach((item) => {
  if (item?.name) serviceMap[item.name] = item.refined_desc || '';
});

const services = activeServices.map((svc) => ({
  name: svc.name || '',
  shortName: svc.short_name || '',
  category: svc.category || '',
  categoryShort: svc.category_short || '',
  callbackData: svc.callback_data || '',
  desc:
    serviceMap[svc.name] ||
    svc.category_short ||
    svc.category ||
    ''
}));

// ======================================================
// 4. Q/A DINAMICHE DA knowledge_fragments
// ======================================================
const knowledgeQA = [];
knowledgeFragments.forEach((fragment) => {
  if (Array.isArray(fragment.sections)) {
    fragment.sections.forEach((item) => {
      if (item?.question && item?.answer) {
        knowledgeQA.push({
          q: item.question,
          a: item.answer
        });
      }
    });
  }
});

const mergedFAQ = uniqueBy(
  [...faqFromSeo, ...knowledgeQA].map((item) => ({
    q: String(item?.q || item?.question || '').trim(),
    a: String(item?.a || item?.answer || '').trim()
  })),
  (item) => `${item.q}__${item.a}`
).filter((item) => item.q && item.a);

// ======================================================
// 5. LABEL DINAMICHE / FALLBACK NEUTRI
// ======================================================
const labels = {
  heroKicker: bot.first_name || 'Business AI',
  uspKicker: sections.usp_kicker || 'Valore',
  uspTitle: sections.usp_headline || sections.usp_title || 'Punti di forza',
  uspIntro: sections.usp_intro || '',

  aboutKicker,
  aboutTitle: aboutHeadline,

  servicesKicker: sections.services_kicker || 'Servizi',
  servicesTitle: sections.services_headline || sections.services_title || 'Servizi attivi',
  servicesIntro: sections.services_intro || '',

  processKicker: sections.process_kicker || 'Metodo',
  processTitle: sections.process_headline || sections.process_title || 'Processo operativo',
  processIntro: sections.process_intro || '',

  faqKicker: sections.faq_kicker || 'FAQ',
  faqTitle: sections.faq_headline || sections.faq_title || 'Domande e risposte',
  faqIntro: sections.faq_intro || '',

  offerKicker: sections.offer_kicker || 'Offerta',
  offerTitle: sections.offer_headline || sections.offer_title || extractOfferTitle(hp.offer_text),
  offerIntro: sections.offer_intro || ''
};

// ======================================================
// 6. HTML BLOCKS
// ======================================================
const uspHTML = usp.length
  ? usp.map((u) => `
    <article class="card">
      <h3>${clean(u.title || '')}</h3>
      <p>${clean(u.text || '')}</p>
    </article>
  `).join('')
  : `
    <article class="card">
      <h3>${esc(companyName)}</h3>
      <p>${clean(hp.company_context_string || od.business_description || '')}</p>
    </article>
  `;

const servicesHTML = services.length
  ? services.map((svc, i) => {
      const icon = getEmoji(`${svc.shortName} ${svc.categoryShort}`);
      return `
        <div class="acc-item">
          <button type="button" onclick="toggleSvc(${i})" class="acc-trigger" aria-expanded="false" aria-controls="svc-${i}">
            <span><small>${esc(icon)}</small> ${esc(svc.name)}</span>
            <i id="arr-${i}">↓</i>
          </button>
          <div id="svc-${i}" class="acc-panel">
            <p>${clean(svc.desc)}</p>
          </div>
        </div>
      `;
    }).join('')
  : `
    <div class="acc-item">
      <button type="button" class="acc-trigger static-trigger">
        <span><small>•</small> Nessun servizio disponibile</span>
        <i>—</i>
      </button>
    </div>
  `;

const processHTML = processSteps.length
  ? processSteps.map((p, i) => `
    <div class="step">
      <b class="step-num">${String(i + 1).padStart(2, '0')}</b>
      <div class="step-content">
        <h4>${clean(p.title || '')}</h4>
        <p>${clean(p.text || '')}</p>
      </div>
    </div>
  `).join('')
  : `
    <div class="step">
      <b class="step-num">01</b>
      <div class="step-content">
        <h4>Analisi</h4>
        <p>${clean(hp.company_context_string || od.business_description || '')}</p>
      </div>
    </div>
  `;

const faqHTML = mergedFAQ.length
  ? mergedFAQ.map((f, i) => `
