          ${siteUrl ? `<p>🌐 <a href="${esc(siteUrl)}" target="_blank" rel="noopener noreferrer">${esc(siteUrl)}</a></p>` : ''}
        </div>
        ${socialLinks ? `<div class="social-links">${socialLinks}</div>` : ''}
      </div>

      <div class="footer-sched">
        <h4>Orari operativi</h4>
        <div style="margin-top:14px;">${hoursHTML}</div>
      </div>
    </div>

    <div class="container">
      <p class="copyright">© ${new Date().getFullYear()} ${esc(companyName)} | SiteBoS Architecture</p>
    </div>
  </footer>

  <script>
    function toggleSvc(i) {
      const p = document.getElementById('svc-' + i);
      const a = document.getElementById('arr-' + i);
      const trigger = a ? a.closest('.acc-trigger') : null;
      if (!p) return;

      const isOpen = p.style.maxHeight && p.style.maxHeight !== '0px';

      document.querySelectorAll('.acc-panel').forEach(el => {
        el.style.maxHeight = '0px';
      });

      document.querySelectorAll('.acc-trigger').forEach(el => {
        el.setAttribute('aria-expanded', 'false');
      });

      document.querySelectorAll('.acc-trigger i').forEach(el => {
        el.style.transform = 'rotate(0deg)';
      });

      if (!isOpen) {
        p.style.maxHeight = p.scrollHeight + 'px';
        if (a) a.style.transform = 'rotate(180deg)';
        if (trigger) trigger.setAttribute('aria-expanded', 'true');
      }
    }
  </script>
</body>
</html>`;

return [{
