const root = $input.first().json;
const hp = root.HoneyPot || {};
const od = root.owner_data || root.ownerdata || {};
const ai = root.MiniSiteJson || {};
const bot = root.owner_bot || root.ownerbot || {};

// 1. Mappa i percorsi degli asset multimediali
const assets = {
    logo: hp.assets?.logo?.url || "",
    hero_image: hp.assets?.photo?.url || "", // Foto dei locali/team dall'HoneyPot
    gallery1: hp.assets?.gallery1?.url || "",
    gallery2: hp.assets?.gallery2?.url || "",
    gallery3: hp.assets?.gallery3?.url || ""
};

// 2. Formatta gli orari operativi programmati nell'HoneyPot
const daysMap = { monday: 'monday', tuesday: 'tuesday', wednesday: 'wednesday', thursday: 'thursday', friday: 'friday', saturday: 'saturday', sunday: 'sunday' };
const hours = hp.availability_schedule?.hours || {};
const availability = {};
for (const key in daysMap) {
    const d = hours[key];
    availability[daysMap[key]] = (d && d.morning?.from) ? `${d.morning.from}-${d.afternoon?.to || d.morning.to}` : "Chiuso";
}

// 3. LOGICA TEMA DI STARTUP VS AGGIORNAMENTO
// Se lo stile esiste già nel database, inviamo "unchanged" per non sovrascrivere le preferenze scelte sulla piattaforma.
// Se è il primissimo deploy (stile vuoto), forziamo "classic" come base di partenza.
const themeParam = (ai.style && ai.style !== "") ? "unchanged" : "classic";

// 4. Compila lo schema ibrido identico all'OutputSchema originale dell'Editor
const minisite_json = {
    style: ai.style || "classic",
    path: ai.path || `posts/${od.vat_number}/index.html`,
    design: {
        font: ai.design?.font || "Plus Jakarta Sans",
        radius: ai.design?.radius || "24px"
    },
    hero: {
        h1: ai.hero?.h1 || "",
        sub: ai.hero?.sub || ""
    },
    seo: {
        title: ai.seo?.title || "",
        description: ai.seo?.description || "",
        keywords: ai.seo?.keywords || [],
        faq: ai.seo?.faq || []
    },
    sections: {
        about: {
            kicker: ai.sections?.about?.kicker || "Mission",
            headline: ai.sections?.about?.headline || "",
            body: ai.sections?.about?.body || ""
        },
        usp: ai.sections?.usp || [],
        process: ai.sections?.process || [],
        services: (hp.active_services || []).map(svc => {
            const icon = (svc.short_name && svc.short_name.match(/\p{Emoji}/u)) ? svc.short_name.match(/\p{Emoji}/u)[0] : '⚡';
            const refinedDesc = ai.service_descriptions?.find(d => d.name === svc.name)?.refined_desc || "";
            return {
                title: svc.name,
                description: refinedDesc.substring(0, 120),
                icon: icon
            };
        })
    },
    service_descriptions: ai.service_descriptions || [],
    offer_text: hp.offer_text || "",
    contact: {
        phone: od.phone || "",
        email: od.email || "",
        address: od.indirizzo || od.address || "",
        city: od.comune || od.city || ""
    },
    assets: assets,
    brand: {
        primary_color: hp.assets?.logo?.meta?.colors?.[0] || "#212D67",
        font: ai.design?.font || "Plus Jakarta Sans"
    },
    availability: availability,
    owner_bot: {
        first_name: bot.first_name || "",
        username: bot.username || ""
    }
};

return [{
    json: {
        ...root,
        assembled_minisite_json: minisite_json,
        theme_param: themeParam
    }
}];
